
.cy-rings {
  display: flex;
  justify-content: space-around;
  align-items: flex-start;
  gap: 12px;
  margin: 18px 0 10px;
}
.cy-stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 9px;
  width: 150px;
}
.cy-val {
  font-size: 26px;
  font-weight: 200;
  color: var(--c-text);
  font-variant-numeric: tabular-nums;
  text-shadow: 0 0 12px rgba(27, 156, 227, 0.4);
  min-width: 48px;
  text-align: center;
}
.cy-lbl {
  font-size: 11px;
  letter-spacing: 2px;
  color: var(--c-text-mute);
  text-align: center;
}
.cy-sub {
  font-size: 10px;
  letter-spacing: 1px;
  color: var(--c-text-dim);
  height: 14px;
  width: 100%;
  text-align: center;
  white-space: nowrap;
}
