
.cy-root {
  position: relative;
  width: 100%;
  max-width: 720px;
  margin: 0 auto;
  border: 1px solid var(--c-border);
  border-radius: 6px;
  overflow: hidden;
  background: var(--c-bg-deep);
  font-family: var(--font-mono);
  color: var(--c-text);
}
.cy-bg {
  position: absolute;
  inset: 0;
  z-index: 0;
  width: 100%;
  height: 100%;
}
.cy-inner {
  position: relative;
  z-index: 2;
  padding: 22px 22px 18px;
}
.cy-tab-content {
  margin-top: 12px;
  min-height: 80px;
}
