
.cy-titlebar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 11px;
  letter-spacing: 2px;
  color: var(--c-text-dim);
  border-bottom: 1px solid var(--c-border);
  padding-bottom: 10px;
}
.cy-brand {
  color: var(--c-blue-deep);
  font-weight: bold;
  letter-spacing: 3px;
}
.cy-model {
  color: var(--c-text-mute);
}
