
.cy-news {
  display: flex;
  flex-direction: column;
  gap: 7px;
  max-height: 240px;
  overflow-y: auto;
  padding-right: 4px;
}
.cy-news-item {
  font-size: 11px;
  line-height: 1.6;
  color: var(--c-text-mute);
  border-left: 2px solid var(--c-border);
  padding: 4px 8px;
  background: var(--c-panel);
  border-radius: 2px;
}
.cy-news-cat {
  display: inline-block;
  color: var(--c-blue);
  font-weight: bold;
  margin-right: 6px;
  letter-spacing: 1px;
}
.cy-news-body {
  color: var(--c-text-mute);
}
