
.cy-origin {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
}
.cy-op {
  border: 1px solid var(--c-border);
  border-left: 3px solid var(--c-blue);
  border-radius: 3px;
  padding: 8px 10px;
  background: var(--c-panel);
}
.cy-op.dead {
  border-left-color: var(--c-red);
  opacity: 0.55;
}
.cy-op-name {
  font-size: 13px;
  color: var(--c-text);
  letter-spacing: 1px;
  margin-bottom: 4px;
}
.cy-op-stance {
  font-size: 11px;
  color: var(--c-blue);
  margin-bottom: 3px;
}
.cy-op-recent {
  font-size: 10px;
  color: var(--c-text-dim);
  line-height: 1.5;
}
@media (max-width: 520px) {
  .cy-origin {
    grid-template-columns: 1fr;
  }
}
